INSERT INTO public.procurement_line_years (line_id, fiscal_year, service, appropriation, appr_code, ba, line_number, title, quantity, unit_cost, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$PROC_NAVY_NA_L0079$$, 2027, $$Navy$$, $$PROC_NAVY$$, $$NAVY$$, NULL, $$79$$, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$ set may not be exact or sum exactly due to rounding.

 Justification:
 FY 2027 funding request includes funding for NMT Service Life Extension Modernization (SLEMOD) Kits procurement of 26 kits (22 Surface Afloat, 2 Sub Afloat and 2 Ashore), with integration and associated
 costs for pre-installation design. SLEMOD Kits provide capability sustainment and enhancements to the Fleet in order to establish system resilience while maintaining perpetual readiness. The NMT Program of
 Record (PoR) has been tasked with extending the lifespan of the Terminal +20 years longer than originally planned. Capability enhancement packages fielded as SLEMOD kits allow the NMT PoR to pace the
 threat while enhancing NMT performance and capability in order to support the Warfighter.

 FY 2027 funding request also includes funding for WAMS procurement of 27 units (20 Surface Afloat, 4 Sub Afloat and 3 Ashore). The FY 2027 funding request also includes the installation of 28 units (26
 Surface Afloat and 2 Ashore) that were procured in FY 2026. Unit Quantities listed in WAMS Ashore are representative of each Ashore Site. Each Ashore site requires a QTY of 60 WAMS modems.




