INSERT INTO public.procurement_line_years (line_id, fiscal_year, service, appropriation, appr_code, ba, line_number, title, quantity, unit_cost, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$PROC_NAVY_NA_L0117$$, 2027, $$Navy$$, $$PROC_NAVY$$, $$NAVY$$, NULL, $$117$$, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$ set may not be exact or sum exactly due to rounding.

 Justification:
 Passenger-Carrying Vehicles - PW (BSVE/NTVE): The FY27 funding reflects a decrease of $258K. The funding is required to support the recapitalization of Navy-owned Passenger-Carrying Vehicle assets at
 locations not serviced by the General Services Administration, where commercial leasing options are unavailable or would exceed 90% of the vehicle purchase price. The current fleet has surpassed its service
 life, exceeded maintenance cost thresholds, and faced increasing scarcity of repair parts.

 Naval Special Warfare (NSW) requires dedicated safety response vehicles for all high-risk training events. Many training areas are inaccessible to civilian ambulances, and NSW is responsible for transporting
 personnel requiring urgent medical care from remote training sites to accessible hard surface roads for ambulance transfer. Additionally, NSW Unit Level Training (ULT) and Squadron Integration Training
 (SIT) rely on a fleet of Passenger-Carrying Vehicles to move small units, task groups, and squadron sized elements for specialized training, exercises, redeployment certification, and events that refine tactics,
 techniques, and procedures.

 NSW manages a large training pipeline, including more than 600 students in Basic Underwater Demolition/SEAL (BUD/S) and Advanced Training Command courses. Personnel must travel between multiple
 offsite ranges and terrain models to train in diverse operational environments that replicate conditions expected in combat. Reliable Passenger-Carrying Vehicles are essential to safely and efficiently support this
 training mission.




