INSERT INTO public.procurement_line_years (line_id, fiscal_year, service, appropriation, appr_code, ba, line_number, title, quantity, unit_cost, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$PROC_NAVY_NA_L0118$$, 2027, $$Navy$$, $$PROC_NAVY$$, $$NAVY$$, NULL, $$118$$, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$ set may not be exact or sum exactly due to rounding.

 Justification:
 FY27 reflects a reduction of $688K from the funding level required to fully support identified replacement needs. General Purpose Trucks are mission critical BSVE assets that enable daily operations across
 Navy public works installations and bases. Continued FY27 investment is essential to recapitalize an aging fleet that has exceeded service life, surpassed maintenance cost thresholds, and now faces significant
 parts scarcity. These vehicles cannot be replaced through the General Services Administration, and commercial leasing is either unavailable or would cost more than 90 percent of the purchase cost. As a result,
 recapitalization remains the only viable path to sustaining operational readiness and meeting critical mission requirements.

 General Purpose Trucks directly support Maritime Special Operations Training across twenty one Naval Special Warfare operational commands, eight staff headquarters, and NSW "A" and "C" schools, including
 Basic Underwater Demolition and advanced skills courses, and they are the primary vehicles used to transport small arms, dive gear, parachutes, special operations equipment, and personnel to weapons
 ranges, free fall sites, combat diving locations, unmanned systems training areas, and special boat training venues. Without timely replacement of these aging vehicles, the Navy faces increasing safety risks,
 degraded training throughput, and reduced ability to prepare SEAL, Special Boat, and Combat Support Teams for high-risk deployments. Continued investment is therefore imperative to sustain mission
 execution, protect personnel, and maintain the operational reliability required across the naval shore enterprise.




