INSERT INTO public.procurement_line_years (line_id, fiscal_year, service, appropriation, appr_code, ba, line_number, title, quantity, unit_cost, prior_year_actual, current_year_enacted, request_amount, fydp_yr1, fydp_yr2, fydp_yr3, fydp_yr4, narrative, content_hash, source_pdf, source_page, ingested_at) VALUES ($$PROC_NAVY_NA_L0140$$, 2027, $$Navy$$, $$PROC_NAVY$$, $$NAVY$$, NULL, $$140$$, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$ set may not be exact or sum exactly due to rounding.

 Justification:
 FY27 funding supports the following:

 Naval Information Warfare Systems Command (NAVWAR) Information Warfare (IW) Shore Platform: FY27 increase is primarily attributed to MILCON Project maturity, removal and shifting Beneficiary Occupancy
 Dates (BOD). P130 will conduct Installation Readiness Review (IRR) and Initial Operating Capability (IOC). P131 will conduct the Full Operational Capability (FOC) and Initial Operating Capability (IOC). P649
 transitions into Intermediate Installation Design Review (IIDR) and Preliminary Installation Design Review (PIDR). P678 will conduct Preliminary Installation Design Review (PIDR) and Critical Design Review
 (CDR). Starting FY27 Project P676 support has been realigned to higher priorities due to TYCOM strategic change. The Program of Record (POR) and Command IT (CIT) systems prepare for and execute
 installation efforts for all of these projects. The IW Shore Program will continue to support the installation efforts by overseeing each POR installation and ensuring the integration of each Platform facility meets
 Full Operational Capability (FOC) and achieves Full and Final Acceptance (FFA).

 Navy Information Forces (NAVIFOR) Collateral Equipment, MILCON Outfitting Project P-013: FY27 increase is due to C4I design delays.

 Telephony: FY27 decrease due to non-recurring costs for engineering, material, and installation; transition of Centrex Time Division Multiplexing (TDM) users to VOIP as well as project integration duties,
 replacement and modernization of aging TDM, also known as "analog" infrastructure at 23 primary and MILCON sites in three regions (Europe, Indian Ocean/Africa, Pacific). Funding will support hardware
 procurement necessary to address the transition of End-of-Life/End-of-Support (EOL/EOS) analog services to Internet Protocol (IP), also known as "digital" voice and video services. Current switches are quickly
 becoming obsolete, raising the cost for supportability and demanding rapid transition to IP technologies as a more cost-effective solution. Legacy TDM services will be able to transition to IP, military-unique
 features and preserve access to cloud services, preventing loss or degradation of communications during critical mission operations. The resulting upgraded infrastructure will provide Navy senior leaders with
 access to critical voice, video, and/or chat services; specifically, features allowing precedence, pre-emption, and Quality of Service (QoS). FY27 funds also support procurement of Shore Telephony capability at
 MILCON P-130 Sigonella and P-131 Souda Bay sites.




